mapper.select:
SELECT
    CASE WHEN COUNT(M.ID) > 0 THEN 1 ELSE 0 END
FROM TBL_MEMBER M
JOIN TBL_SOCIAL_MEMBER SM ON M.ID = SM.MEMBER_ID
WHERE M.MEMBER_EMAIL = #{memberEmail}
  AND SM.SOCIAL_MEMBER_PROVIDER = #{socialMemberProvider}

mapper.update:
UPDATE TBL_MEMBER
MEMBER_NICKNAME = #{memberNickname}, MEMBER_PROFILE_IMAGE_URL = #{memberProfileImageUrl}, MEMBER_PHONE = #{memberPhone}, MEMBER_PASSWORD = #{memberPassword},
WHERE ID = #{id}

UPDATE TBL_MEMBER
SET MEMBER_PROFILE_IMAGE_URL = #{memberProfileImageUrl}
WHERE ID = #{id}
